export const meta = {
  name: 'understand-champion-circuit',
  description: 'Map backend auth/roles, venue domain, admin frontend, and design language for turf-owner panel design',
  phases: [
    { title: 'Map', detail: 'parallel readers over backend + frontend subsystems' },
  ],
}

phase('Map')

const SCHEMA = {
  type: 'object',
  properties: {
    summary: { type: 'string', description: 'Dense factual summary of everything found, with file:line references' },
    keyFacts: { type: 'array', items: { type: 'string' }, description: 'Bullet facts critical for implementing a turf-owner admin panel' },
  },
  required: ['summary', 'keyFacts'],
}

const ROOT = 'C:/Users/nikhil.jain_int/Downloads/champion-circuit'

const areas = [
  {
    key: 'backend-auth',
    prompt: `Read these files in ${ROOT}/backend: app/core/security.py, app/api/deps.py, app/api/routes/auth.py, app/models/user.py, app/schemas/auth.py, app/schemas/user.py, app/services/users.py. Report: how auth works (JWT? token payload fields?), user model fields (is there a role/is_admin field? what roles exist?), how admin access is gated (which dependency), signup/login endpoints and their request/response shapes, password hashing, google auth if any. Include exact code excerpts for the role/permission gating and token creation. Cite file:line.`,
  },
  {
    key: 'backend-venues',
    prompt: `Read these files in ${ROOT}/backend: app/models/venue.py, app/schemas/venue.py, app/api/routes/venues.py, app/services/venue.py, and also app/api/routes/admin.py. Report: the full Venue/Turf data model (every column, relationships — courts? slots? pricing? images?), every venue-related API endpoint (method, path, auth requirement, request/response shape), what admin.py exposes for venue management (create/update/delete turf endpoints? owner field?), and any owner/ownership concept in the model. Also check app/db/migrations.py for how schema migrations are handled. Cite file:line with exact field names.`,
  },
  {
    key: 'frontend-admin',
    prompt: `Read these files in ${ROOT}/frontend/src: pages/admin/AdminLoginPage.tsx, pages/admin/AdminDashboardPage.tsx, pages/admin/AdminTurfsPage.tsx, lib/adminAccess.ts, and list+read what's in pages/staff/ directory. Report: how admin login works (endpoint, token storage key), how admin routes are guarded, what AdminTurfsPage can already do (CRUD operations? which API calls?), the layout/nav structure of the admin area, and what the staff pages are for. Cite file:line and exact localStorage keys / API paths.`,
  },
  {
    key: 'frontend-app-shell',
    prompt: `Read these files in ${ROOT}/frontend/src: App.tsx (or main.tsx / router setup — find the route table), lib/api.ts, lib/ccApi.ts, pages/LoginPage.tsx, pages/TurfBrowsePage.tsx, pages/TurfDetailPage.tsx. Report: the complete route table (path → component), how the regular user auth flow works (login endpoint, token storage, auth context/hook), how api.ts/ccApi.ts structure API calls (base URL, auth header injection, error handling), and how TurfBrowsePage + TurfDetailPage fetch and render turf data (which endpoints, which fields displayed — images, pricing, slots, amenities). Cite file:line.`,
  },
  {
    key: 'design-language',
    prompt: `Study the visual design language of ${ROOT}/frontend/src. Read: index.css or any global css, tailwind config if present (check frontend/ root for tailwind.config), 2-3 representative pages (pages/TurfBrowsePage.tsx, pages/admin/AdminDashboardPage.tsx, pages/ProfilePage.tsx), and components/ui/ directory contents (list it, read Navbar.tsx and 2 others). Report: styling approach (tailwind? css modules? inline?), color palette (exact hex/css vars — background, accent, text), typography (fonts), common UI patterns (card styles, button styles, border-radius, glassmorphism?, gradients, animation patterns with framer-motion), dark/light theme. Give concrete reusable class strings or style objects that new admin pages should copy to blend in. Cite file:line.`,
  },
]

const results = await parallel(areas.map(a => () =>
  agent(a.prompt + ' Return raw dense facts, not prose for humans.', { label: `map:${a.key}`, phase: 'Map', schema: SCHEMA })
))

return Object.fromEntries(areas.map((a, i) => [a.key, results[i]]))

