1	/**
2	 * Turf Owner Dashboard — /staff/venue
3	 * Turf owner manages their venue: listings, bookings, tournaments, match admin assignment.
4	 */
5	import { useEffect, useState, type FormEvent } from 'react';
6	import { useNavigate } from 'react-router-dom';
7	import { useAuth } from '../../context/AuthContext';
8	import { ccApi, type VenueListing, type Tournament } from '../../lib/ccApi';
9	import { ApiError } from '../../lib/api';
10	
11	const BASE = import.meta.env.VITE_API_URL ?? 'http://127.0.0.1:8000';
12	
13	async function staffReq<T>(path: string, init: RequestInit = {}): Promise<T> {
14	  const token = localStorage.getItem('cc_token');
15	  const isForm = init.body instanceof FormData;
16	  const res = await fetch(`${BASE}${path}`, {
17	    ...init,
18	    headers: {
19	      ...(isForm ? {} : { 'Content-Type': 'application/json' }),
20	      ...(token ? { Authorization: `Bearer ${token}` } : {}),
21	      ...(init.headers as Record<string, string>),
22	    },
23	  });
24	  if (!res.ok) {
25	    const b = await res.json().catch(() => ({}));
26	    throw new ApiError(res.status, b.detail ?? `HTTP ${res.status}`);
27	  }
28	  return res.json() as Promise<T>;
29	}
30	
31	type Tab = 'overview' | 'listings' | 'bookings' | 'tournaments';
32	
33	interface VenueData {
34	  venue: Record<string, unknown> | null;
35	  listings: VenueListing[];
36	  bookings: Record<string, unknown>[];
37	}
38	
39	export function TurfOwnerPage() {
40	  const { user, signOut } = useAuth();
41	  const navigate = useNavigate();
42	  const [tab, setTab] = useState<Tab>('overview');
43	  const [data, setData] = useState<VenueData>({ venue: null, listings: [], bookings: [] });
44	  const [tournaments, setTournaments] = useState<Tournament[]>([]);
45	  const [msg, setMsg] = useState('');
46	  const [loading, setLoading] = useState(true);
47	
48	  useEffect(() => {
49	    if (!user) { navigate('/staff-login', { replace: true }); return; }
50	    if (!user.is_venue_owner && !user.is_admin) { navigate('/staff/match', { replace: true }); return; }
51	    Promise.all([
52	      staffReq<VenueData>('/api/staff/my-venue'),
53	      staffReq<Tournament[]>('/api/staff/my-tournaments'),
54	    ]).then(([vd, ts]) => { setData(vd); setTournaments(ts); })
55	      .catch(() => setMsg('Could not load venue data.'))
56	      .finally(() => setLoading(false));
57	  }, [user, navigate]);
58	
59	  if (!user?.is_venue_owner && !user?.is_admin) return null;
60	
61	  const venueId = data.venue ? (data.venue as { id: number }).id : null;
62	
63	  return (
64	    <div className="staff-shell">
65	      <aside className="staff-sidebar">
66	        <div className="staff-sidebar__brand">
67	          <img src="/branding/cc-mark.png" alt="CC" width={32} />
68	          <span>Venue Portal</span>
69	        </div>
70	        {(['overview', 'listings', 'bookings', 'tournaments'] as Tab[]).map((t) => (
71	          <button key={t} type="button"
72	            className={`staff-nav-btn${tab === t ? ' staff-nav-btn--active' : ''}`}
73	            onClick={() => setTab(t)}>
74	            {t.charAt(0).toUpperCase() + t.slice(1)}
75	          </button>
76	        ))}
77	        {user.is_admin && (
78	          <button type="button" className="staff-nav-btn" onClick={() => navigate('/staff/admin')}>
79	            ← Super Admin
80	          </button>
81	        )}
82	        <button type="button" className="staff-nav-btn staff-nav-btn--logout"
83	          onClick={() => { signOut(); navigate('/staff-login'); }}>
84	          Sign out
85	        </button>
86	      </aside>
87	
88	      <main className="staff-main">
89	        {loading ? <div className="staff-loading">Loading venue…</div> : (
90	          <>
91	            {msg ? <p className="staff-msg">{msg}</p> : null}
92	            {tab === 'overview' && <VenueOverview data={data} />}
93	            {tab === 'listings' && venueId ? <VenueListings venueId={venueId} listings={data.listings} onMsg={setMsg} /> : null}
94	            {tab === 'bookings' && <VenueBookings bookings={data.bookings} />}
95	            {tab === 'tournaments' && <VenueTournaments tournaments={tournaments} onMsg={setMsg} venueId={venueId} />}
96	          </>
97	        )}
98	      </main>
99	    </div>
100	  );
101	}
102	
103	function VenueOverview({ data }: { data: VenueData }) {
104	  const v = data.venue as Record<string, string | number | boolean> | null;
105	  if (!v) return (
106	    <div className="staff-section">
107	      <h2 className="staff-h2">My Venue</h2>
108	      <p className="muted">No venue yet. Contact super admin to set up your venue, or create one:</p>
109	      <a href="/api/docs#/venues/create_my_venue_api_venues_post" target="_blank" className="btn btn-secondary btn-sm" style={{ marginTop: 12 }}>
110	        Create via API docs →
111	      </a>
112	    </div>
113	  );
114	  return (
115	    <div className="staff-section">
116	      <h2 className="staff-h2">My Venue</h2>
117	      <div className="staff-venue-overview">
118	        <div className="staff-venue-overview__row"><span>Name</span><strong>{String(v.name)}</strong></div>
119	        <div className="staff-venue-overview__row"><span>City</span><strong>{String(v.city)}</strong></div>
120	        <div className="staff-venue-overview__row"><span>Address</span><strong>{String(v.address_line1)}</strong></div>
121	        <div className="staff-venue-overview__row"><span>Phone</span><strong>{String(v.phone)}</strong></div>
122	        <div className="staff-venue-overview__row"><span>Verified</span><strong>{v.is_verified ? '✓ Yes' : '✗ Pending'}</strong></div>
123	        <div className="staff-venue-overview__row"><span>Listings</span><strong>{data.listings.length}</strong></div>
124	        <div className="staff-venue-overview__row"><span>Bookings</span><strong>{data.bookings.length}</strong></div>
125	      </div>
126	    </div>
127	  );
128	}
