import { BrowserRouter, Navigate, Route, Routes } from 'react-router-dom';
import { AuthProvider } from './context/AuthContext';
import { CityProvider } from './context/CityContext';
import { PlatformProvider } from './context/PlatformContext';
import { PublicLayout } from './layouts/PublicLayout';
import { AppLayout } from './layouts/AppLayout';
import { AdminLayout } from './layouts/AdminLayout';
import { RequireAuth, RequireAdmin } from './routes/AuthGuards';

import { LandingPage } from './pages/LandingPage';
import { AboutPage } from './pages/AboutPage';
import { LoginPage } from './pages/LoginPage';
import { SignupPage } from './pages/SignupPage';
import { ForgotPasswordPage } from './pages/ForgotPasswordPage';

import { TurfBrowsePage } from './pages/TurfBrowsePage';
import { VenueDetailPage } from './pages/VenueDetailPage';
import { EsportsBrowsePage } from './pages/EsportsBrowsePage';
import { EsportsTournamentPage } from './pages/EsportsTournamentPage';
import { LeaderboardPage } from './pages/LeaderboardPage';
import { VouchersPage } from './pages/VouchersPage';
import { MyVoucherPage } from './pages/MyVoucherPage';
import { NewsPage, NewsArticlePage } from './pages/NewsPage';

import { ProfilePage } from './pages/ProfilePage';
import { BookingsPage } from './pages/BookingsPage';
import { MyMatchesPage } from './pages/MyMatchesPage';

import { AdminLoginPage } from './pages/admin/AdminLoginPage';
import { AdminDashboardPage } from './pages/admin/AdminDashboardPage';
import { AdminTurfsPage } from './pages/admin/AdminTurfsPage';
import { AdminTournamentsPage } from './pages/admin/AdminTournamentsPage';
import { AdminLeaderboardPage } from './pages/admin/AdminLeaderboardPage';
import { AdminUsersPage } from './pages/admin/AdminUsersPage';
import { AdminContentPage } from './pages/admin/AdminContentPage';
import { ActivityLogPage } from './pages/admin/ActivityLogPage';

// Staff portals — hidden, full-screen, no public navbar
import { StaffLoginPage } from './pages/staff/StaffLoginPage';
import { SuperAdminPage } from './pages/staff/SuperAdminPage';
import { TurfOwnerPage } from './pages/staff/TurfOwnerPage';
import { MatchAdminPage } from './pages/staff/MatchAdminPage';

export default function App() {
  return (
    <BrowserRouter>
      <AuthProvider>
        <CityProvider>
          <PlatformProvider>
            <Routes>

              {/* ── Staff portals (no public layout, full screen) ── */}
              <Route path="staff-login" element={<StaffLoginPage />} />
              <Route path="staff/admin" element={<SuperAdminPage />} />
              <Route path="staff/venue" element={<TurfOwnerPage />} />
              <Route path="staff/match" element={<MatchAdminPage />} />

              {/* ── Public pages with navbar ── */}
              <Route element={<PublicLayout />}>
                <Route index element={<LandingPage />} />
                <Route path="about" element={<AboutPage />} />
                <Route path="login" element={<LoginPage />} />
                <Route path="signup" element={<SignupPage />} />
                <Route path="register" element={<Navigate to="/signup" replace />} />
                <Route path="forgot-password" element={<ForgotPasswordPage />} />

                <Route path="turf" element={<TurfBrowsePage />} />
                <Route path="venue/:id" element={<VenueDetailPage />} />

                <Route path="esports" element={<EsportsBrowsePage />} />
                <Route path="esports/tournament/:id" element={<EsportsTournamentPage />} />

                <Route
                  path="leaderboard"
                  element={
                    <RequireAuth>
                      <LeaderboardPage />
                    </RequireAuth>
                  }
                />

                <Route path="vouchers" element={<VouchersPage />} />
                <Route path="my-voucher" element={<MyVoucherPage />} />

                <Route path="news" element={<NewsPage />} />
                <Route path="news/:id" element={<NewsArticlePage />} />
              </Route>

              {/* ── Authenticated user pages ── */}
              <Route element={<RequireAuth><AppLayout /></RequireAuth>}>
                <Route path="profile" element={<ProfilePage />} />
                <Route path="bookings" element={<BookingsPage />} />
                <Route path="my-matches" element={<MyMatchesPage />} />
                <Route path="my-vouchers" element={<MyVoucherPage />} />
              </Route>

              {/* ── Old admin panel (legacy) ── */}
              <Route path="admin/login" element={<AdminLoginPage />} />
              <Route element={<RequireAdmin><AdminLayout /></RequireAdmin>}>
                <Route path="admin" element={<AdminDashboardPage />} />
                <Route path="admin/turfs" element={<AdminTurfsPage />} />
                <Route path="admin/tournaments" element={<AdminTournamentsPage />} />
                <Route path="admin/leaderboard" element={<AdminLeaderboardPage />} />
                <Route path="admin/users" element={<AdminUsersPage />} />
                <Route path="admin/content" element={<AdminContentPage />} />
                <Route path="admin/activity" element={<ActivityLogPage />} />
              </Route>

              <Route path="platform" element={<Navigate to="/turf" replace />} />
              <Route path="*" element={<Navigate to="/" replace />} />

            </Routes>
          </PlatformProvider>
        </CityProvider>
      </AuthProvider>
    </BrowserRouter>
  );
}

/**
 * Hidden staff login — not linked from any public page.
 * Access: type /staff-login directly in the browser.
 *
 * On successful login:
 *  - is_admin=true  → /staff/admin
 *  - is_venue_owner=true → /staff/venue
 *  - tournament admin → /staff/match
 *  - none of the above → "no staff access" error
 */
import { useState, type FormEvent } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import { api, ApiError } from '../../lib/api';

export function StaffLoginPage() {
  const { setToken, user } = useAuth();
  const navigate = useNavigate();
  const [identifier, setIdentifier] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  async function handleSubmit(e: FormEvent) {
    e.preventDefault();
    setError('');
    setLoading(true);
    try {
      const res = await api.login(identifier.trim(), password);
      await setToken(res.access_token);
      // setToken fetches /me — check role after
    } catch (err) {
      setError(err instanceof ApiError ? err.message : 'Login failed.');
      setLoading(false);
      return;
    }
    setLoading(false);
  }

  // After token is set, user is loaded — redirect based on role
  if (user) {
    if (user.is_admin) {
      navigate('/staff/admin', { replace: true });
    } else if (user.is_venue_owner) {
      navigate('/staff/venue', { replace: true });
    } else {
      // Could be a match admin — send to match admin portal
      navigate('/staff/match', { replace: true });
    }
    return null;
  }

  return (
    <div className="staff-login-page">
      <div className="staff-login-card">
        <img src="/branding/cc-mark.png" alt="Champion Circuit" className="staff-login-logo" />
        <p className="staff-login-eyebrow">Staff Portal</p>
        <h1 className="staff-login-title">Sign in</h1>
        <p className="staff-login-sub">
          This page is for Champion Circuit staff only.<br />
          Not for regular users.
        </p>

        <form className="auth-form" onSubmit={(e) => void handleSubmit(e)}>
          <div className="auth-field">
            <label className="auth-label">Username or email</label>
            <input
              className="auth-input"
              type="text"
              placeholder="admin or turf@..."
              value={identifier}
              onChange={(e) => setIdentifier(e.target.value)}
              required
              autoFocus
            />
          </div>
          <div className="auth-field">
            <label className="auth-label">Password</label>
            <input
              className="auth-input"
              type="password"
              placeholder="••••••••"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              required
            />
          </div>
          {error ? <p className="auth-error">{error}</p> : null}
          <button type="submit" className="btn btn-primary auth-submit" disabled={loading}>
            {loading ? 'Signing in…' : 'Sign in to staff portal'}
          </button>
        </form>
      </div>
    </div>
  );
}

