/**
 * UI E2E: turf-owner logs in at /partner-login, edits their turf,
 * then an anonymous user browses the public venue page and sees the changes.
 */
const { chromium } = require('playwright-core');
const path = require('path');

const APP = 'http://127.0.0.1:5174';
const SHOTS = path.join(__dirname, 'shots');
require('fs').mkdirSync(SHOTS, { recursive: true });

let pass = 0, fail = 0;
const failures = [];
function check(name, cond, detail = '') {
  if (cond) { pass++; console.log(`  ok    ${name}`); }
  else { fail++; failures.push(name + ' ' + detail); console.log(`  FAIL  ${name} ${detail}`); }
}

(async () => {
  const browser = await chromium.launch({ channel: 'msedge', headless: true });

  // ── Owner session ──────────────────────────────────────────────
  const owner = await browser.newContext({ viewport: { width: 1440, height: 900 } });
  const page = await owner.newPage();
  const errors = [];
  page.on('pageerror', (e) => errors.push(String(e)));

  console.log('== Partner login ==');
  await page.goto(`${APP}/partner-login`);
  await page.waitForSelector('text=Partner Portal');
  check('partner-login page shows Partner Portal branding', true);
  await page.screenshot({ path: path.join(SHOTS, '01-partner-login.png') });

  await page.fill('input[placeholder="admin or turf@..."]', 'turfowner1');
  await page.fill('input[type="password"]', 'passw0rd123');
  await page.click('button:has-text("Sign in to staff portal")');
  await page.waitForURL('**/staff/venue', { timeout: 15000 });
  check('owner redirected to /staff/venue', page.url().includes('/staff/venue'));

  console.log('== Overview ==');
  await page.waitForSelector('.staff-stats-grid', { timeout: 15000 });
  const venueName = await page.textContent('.staff-section .staff-h2');
  check('overview shows venue name', (venueName || '').includes('Alpha Turf Arena'), venueName);
  await page.screenshot({ path: path.join(SHOTS, '02-overview.png'), fullPage: true });

  console.log('== Edit listing ==');
  await page.click('.staff-nav-btn:has-text("Listings")');
  await page.waitForSelector('.staff-card');
  await page.click('.staff-card button:has-text("Edit")');
  await page.waitForSelector('.staff-listing-editor');
  await page.screenshot({ path: path.join(SHOTS, '03-listing-editor.png'), fullPage: true });

  const titleInput = page.locator('.staff-listing-editor label:has-text("Title") input');
  await titleInput.fill('Cricket Turf A (UI-Edited)');
  const priceInput = page.locator('.staff-listing-editor label:has-text("Price / hour") input');
  await priceInput.fill('2000');
  const descArea = page.locator('.staff-listing-editor label:has-text("Description") textarea');
  await descArea.fill('Edited from the owner panel UI');
  await page.click('button:has-text("Save details")');
  await page.waitForSelector('.auth-success:has-text("Listing updated")', { timeout: 10000 });
  check('listing save shows success banner', true);

  console.log('== Add amenity via UI ==');
  await page.waitForSelector('.staff-card button:has-text("Edit")');
  await page.click('.staff-card button:has-text("Edit")'); // re-open editor (list re-rendered after reload)
  await page.waitForSelector('.staff-listing-editor');
  await page.fill('input[placeholder="Add amenity (e.g. Floodlit)"]', 'Cafeteria');
  await page.click('.staff-subsection button:has-text("Add")');
  await page.waitForSelector('.staff-chip:has-text("Cafeteria")', { timeout: 10000 });
  check('amenity chip appears after add', true);

  console.log('== Add slot via UI ==');
  await page.click('button:has-text("+ Add slot")');
  await page.selectOption('.staff-subsection select.auth-input', '2'); // Wed
  const times = page.locator('.staff-subsection input[type="time"]');
  await times.nth(0).fill('20:00');
  await times.nth(1).fill('21:00');
  await page.click('.staff-inline-form button:has-text("Add")');
  await page.waitForSelector('.auth-success:has-text("Slot added")', { timeout: 10000 });
  check('slot added via UI', true);
  await page.screenshot({ path: path.join(SHOTS, '04-listing-after-edits.png'), fullPage: true });

  console.log('== Edit venue details ==');
  await page.click('.staff-nav-btn:has-text("My Venue")');
  await page.waitForSelector('text=Edit venue details');
  const venueDesc = page.locator('form > label:has-text("Description") textarea');
  await venueDesc.fill('Venue description edited via owner panel');
  await page.click('button:has-text("Save changes")');
  await page.waitForSelector('.auth-success:has-text("Venue updated")', { timeout: 10000 });
  check('venue save shows success banner', true);
  await page.screenshot({ path: path.join(SHOTS, '05-venue-editor.png'), fullPage: true });

  console.log('== Bookings status ==');
  await page.click('.staff-nav-btn:has-text("Bookings")');
  await page.waitForSelector('.staff-table');
  await page.selectOption('.staff-status-select', 'confirmed');
  await page.waitForSelector('.auth-success:has-text("marked confirmed")', { timeout: 10000 });
  check('booking status changed via UI', true);
  await page.screenshot({ path: path.join(SHOTS, '06-bookings.png'), fullPage: true });

  // ── Anonymous user sees the changes ────────────────────────────
  console.log('== Public reflection (anonymous browser) ==');
  const anon = await browser.newContext({ viewport: { width: 1440, height: 900 } });
  const pub = await anon.newPage();
  await pub.goto(`${APP}/venue/1`);
  await pub.waitForSelector('text=Alpha Turf Arena', { timeout: 15000 });
  const body = await pub.textContent('body');
  check('public page shows edited listing title', body.includes('Cricket Turf A (UI-Edited)'));
  check('public page shows edited venue description', body.includes('Venue description edited via owner panel'));
  check('public page shows new price 2000', body.includes('2000'));
  check('public page shows Cafeteria amenity', body.includes('Cafeteria'));
  await pub.screenshot({ path: path.join(SHOTS, '07-public-venue.png'), fullPage: true });

  console.log('== Guard: anonymous cannot open /staff/venue ==');
  await pub.goto(`${APP}/staff/venue`);
  await pub.waitForURL('**/staff-login', { timeout: 10000 }).catch(() => {});
  check('anonymous redirected to staff-login', pub.url().includes('staff-login'));

  check('no page JS errors in owner session', errors.length === 0, errors.slice(0, 3).join(' | '));

  await browser.close();
  console.log(`\nRESULT: ${pass} passed, ${fail} failed`);
  if (failures.length) failures.forEach((f) => console.log('  -', f));
  process.exit(fail ? 1 : 0);
})().catch((e) => { console.error('SCRIPT ERROR:', e.message); process.exit(2); });

