    { title: 'Verify', detail: 'adversarial verification of each finding' },
  ],
}

const ROOT = 'C:/Users/nikhil.jain_int/Downloads/champion-circuit'
const CTX = `
The diff under review implements a turf-owner admin panel in a FastAPI + React app.
Get the diff with: cd ${ROOT} && git diff -- backend/app frontend/src
