        required: ['file', 'title', 'detail', 'severity'],
      },
    },
  },
  required: ['findings'],
}

const VERDICT = {
  type: 'object',
  properties: {
    isReal: { type: 'boolean', description: 'true only if the defect is real and reachable' },
    reasoning: { type: 'string' },
  },
  required: ['isReal', 'reasoning'],
}

const DIMENSIONS = [
  {
    key: 'security',
    prompt: `You are a security reviewer. ${CTX}
Hunt ONLY for security defects in the CHANGED code: broken authz (can a non-owner mutate another venue's data through any new endpoint or an overlooked object path?), IDOR via nested ids (listing_id/photo_id/slot_id/booking_id mismatches), mass-assignment via ListingUpdate/VenueUpdate (any field that should not be user-settable, e.g. can an owner set is_verified or price to negative? check schema constraints), privilege escalation via create_venue granting is_venue_owner, injection, unsafe file upload handling. Report only defects with a concrete exploit path.`,
  },
  {
    key: 'correctness',
    prompt: `You are a correctness reviewer. ${CTX}
Hunt ONLY for logic bugs in the CHANGED backend code: update_listing/update_venue partial-update semantics (None vs unset vs empty; can a client null-out a field unintentionally or be unable to clear one?), booking status transitions, slot deletion with existing bookings referencing the slot (FK ondelete=RESTRICT on bookings.slot_id? check the model), serialize_listing slots exposure breaking any consumer, list_listings include_inactive leaking hidden listings anywhere public, category validation, paise/rupee rounding (Math.round on frontend vs int on backend). Report only real, reachable defects.`,
  },
  {
    key: 'frontend-state',
    prompt: `You are a React reviewer. ${CTX}
Review frontend/src/pages/staff/TurfOwnerPage.tsx (full rewrite) for state bugs: stale form state after reload() (ListingEditForm/VenueEditor useState initialized from props without key/useEffect sync — when does the UI show wrong data?), race conditions from concurrent mutations, expandedId behavior when listing list changes, error handling that leaves spinners stuck, msg banner showing wrong kind, controlled-input NaN from Number('') on number inputs, price rounding display (e.g. paise 150050/100=1500.5 into number input), file input reuse, booking select optimistic update. Report only bugs a user would actually hit.`,
  },
  {
    key: 'consistency',
    prompt: `You are an API-contract reviewer. ${CTX}
Cross-check frontend expectations vs backend responses in the diff: ccApi types (VenueListing.slots, StaffBooking, MyVenueData) vs serialize_listing/my-venue payloads (field names, optionality — e.g. staff my-venue bookings lack num_players; venue detail includes address_line2? VenueEditor loads address_line2 from venue but serialize_venue may not return it — check!), update payload shapes vs pydantic schemas, /partner-login route alias correctness, VenueDetailPage/TurfBrowsePage still typechecking against changed VenueListing (slots now required — do public pages construct VenueListing objects anywhere?). Report concrete mismatches only.`,
  },
]

phase('Review')
const results = await pipeline(
  DIMENSIONS,
  d => agent(d.prompt + ' Return findings via the schema; empty array if none.', {
    label: `find:${d.key}`, phase: 'Review', schema: FINDINGS,
  }),
  (review, dim) => {
    const fs = (review?.findings ?? []).slice(0, 8)
    if (!fs.length) return []
    return parallel(fs.map(f => () =>
      agent(`You are a skeptical verifier. ${CTX}
Finding claimed by a ${dim.key} reviewer:
FILE: ${f.file} ${f.line ? 'LINE ~' + f.line : ''}
TITLE: ${f.title}
DETAIL: ${f.detail}
Read the actual code and try to REFUTE this. It is only real if the failure is reachable in practice. Consider schema validation layers, auth gates, and how the UI actually calls the API. Default isReal=false if uncertain.`,
        { label: `verify:${f.title.slice(0, 40)}`, phase: 'Verify', schema: VERDICT })
        .then(v => ({ ...f, dimension: dim.key, verdict: v }))
    ))
  }
)

const all = results.filter(Boolean).flat().filter(Boolean)
const confirmed = all.filter(f => f.verdict?.isReal)
const rejected = all.filter(f => !f.verdict?.isReal).map(f => ({ title: f.title, why: f.verdict?.reasoning?.slice(0, 200) }))
return { confirmed, rejectedCount: rejected.length, rejected }

